package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetAllowMissingColumnNames() throws Exception {
        // Given
        CSVFormat csvFormat = (CSVFormat) CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                Character.class, Character.class, boolean.class, boolean.class, String.class, String.class, Object[].class,
                String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class)
                .newInstance(',', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "\\N",
                        new Object[]{"Header1", "Header2"}, new String[]{"Comment1", "Comment2"}, false, true, false, true,
                        false);
        boolean expectedResult = true;

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(expectedResult, result);
    }
}
